"use client";

export { DiffView, type DiffViewProps } from "./diff-view";
export { parseDiff, computeDiff, resolveDiffInput } from "@/lib/diff";
export type { ParsedDiff, DiffHunk, DiffChange, ChangeType, DiffInput } from "@/lib/diff";

"use client";

import {
  useState,
  useRef,
  useMemo,
  type Ref,
  type RefObject,
  type KeyboardEvent,
} from "react";
import { cn } from "@/lib/utils";
import {
  type ParsedDiff,
  type DiffInputPatch,
  type DiffInputCompare,
  type DiffInputParsed,
  resolveDiffInput,
} from "@/lib/diff";
import { useNavigation } from "@/hooks/use-navigation";
import { Kbd } from "../kbd/kbd";
import { UnifiedView } from "./diff-view-unified";
import { SplitView } from "./diff-view-split";

interface DiffViewBaseProps {
  mode?: "unified" | "split";
  showLineNumbers?: boolean;
  disableWordDiff?: boolean;
  label?: string;
  className?: string;
  ref?: Ref<HTMLDivElement>;
}

export type DiffViewProps = (
  | DiffInputPatch
  | DiffInputCompare
  | DiffInputParsed
) &
  DiffViewBaseProps;

interface ActiveHunkState {
  parsedIdentity: string;
  value: string;
}

function getParsedDiffIdentity(parsed: ParsedDiff): string {
  return JSON.stringify([
    parsed.oldPath,
    parsed.newPath,
    parsed.hunks.map((hunk) => [
      hunk.oldStart,
      hunk.oldCount,
      hunk.newStart,
      hunk.newCount,
      hunk.heading,
      hunk.changes.map((change) => [
        change.type,
        change.content,
        change.oldLine,
        change.newLine,
      ]),
    ]),
  ]);
}

function resolveActiveHunk(
  activeHunkState: ActiveHunkState | null,
  parsedIdentity: string,
  hunkCount: number,
): string | null {
  if (activeHunkState?.parsedIdentity !== parsedIdentity) return null;

  const activeIndex = Number(activeHunkState.value);
  if (!Number.isInteger(activeIndex) || activeIndex < 0 || activeIndex >= hunkCount) {
    return null;
  }

  return activeHunkState.value;
}

function FileHeader({
  oldPath,
  newPath,
}: {
  oldPath: string | null;
  newPath: string | null;
}) {
  if (!oldPath && !newPath) return null;

  const label =
    oldPath && newPath && oldPath !== newPath
      ? `${oldPath} → ${newPath}`
      : (oldPath ?? newPath);

  return (
    <div className="px-2 py-1 bg-muted/50 border-b border-border text-muted-foreground truncate">
      {label}
    </div>
  );
}

function DiffContent({
  parsed,
  mode,
  showLineNumbers,
  disableWordDiff,
  activeHunk,
  onKeyDown,
  containerRef,
}: {
  parsed: ParsedDiff;
  mode: "unified" | "split";
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLElement | null>;
}) {
  if (parsed.hunks.length === 0) {
    return (
      <div
        className="p-4 text-center text-muted-foreground text-sm"
        role="status"
      >
        No changes
      </div>
    );
  }
  if (mode === "split") {
    return (
      <SplitView
        parsed={parsed}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
    );
  }
  return (
    <UnifiedView
      parsed={parsed}
      showLineNumbers={showLineNumbers}
      disableWordDiff={disableWordDiff}
      activeHunk={activeHunk}
      onKeyDown={onKeyDown}
      containerRef={containerRef}
    />
  );
}

export function DiffView(props: DiffViewProps) {
  const {
    mode = "unified",
    showLineNumbers = false,
    disableWordDiff = false,
    label,
    className,
    ref,
  } = props;
  const patch = "patch" in props ? props.patch : undefined;
  const before = "before" in props ? props.before : undefined;
  const after = "after" in props ? props.after : undefined;
  const diff = "diff" in props ? props.diff : undefined;
  const parsed = useMemo(
    () => resolveDiffInput(props),
    [patch, before, after, diff],
  );
  const containerRef = useRef<HTMLElement | null>(null);
  const parsedIdentity = useMemo(() => getParsedDiffIdentity(parsed), [parsed]);
  const [activeHunkState, setActiveHunkState] = useState<ActiveHunkState | null>(null);
  const activeHunk = resolveActiveHunk(activeHunkState, parsedIdentity, parsed.hunks.length);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "button",
    highlighted: activeHunk,
    onHighlightChange: (value) => { if (value !== null) setActiveHunkState({ parsedIdentity, value }); },
    upKeys: ["k"],
    downKeys: ["j"],
    wrap: false,
    moveFocus: false,
  });

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      setActiveHunkState(null);
      return;
    }
    navKeyDown(e);
  };

  const activeIndex = activeHunk != null ? Number(activeHunk) : null;
  const activeHunkData = activeIndex != null ? parsed.hunks[activeIndex] : undefined;
  const announcement =
    activeIndex != null && activeHunkData
      ? `Hunk ${activeIndex + 1} of ${parsed.hunks.length}${activeHunkData.heading ? `: ${activeHunkData.heading}` : ""}`
      : "";

  return (
    <div
      ref={ref}
      role="region"
      aria-roledescription="diff"
      aria-label={label ?? "Diff output"}
      className={cn(
        "group bg-background border border-border font-mono text-xs",
        className,
      )}
    >
      <FileHeader oldPath={parsed.oldPath} newPath={parsed.newPath} />
      {parsed.hunks.length > 0 && (
        <div className="hidden group-focus-within:flex items-center gap-1 px-2 py-0.5 text-[10px] text-muted-foreground border-b border-border">
          <Kbd size="sm">j</Kbd>
          <Kbd size="sm">k</Kbd>
          <span>navigate hunks</span>
        </div>
      )}
      <DiffContent
        parsed={parsed}
        mode={mode}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
      <div className="sr-only" aria-live="polite" aria-atomic="true">
        {announcement}
      </div>
    </div>
  );
}

"use client";

import type { ChangeType, WordSegment } from "@/lib/diff";

export const LINE_STYLE: Record<ChangeType | "hunk", string | undefined> = {
  remove: "text-destructive",
  add: "text-success",
  context: undefined,
  hunk: "text-muted-foreground bg-muted/20 -mx-2 px-2",
};

export const SR_LABEL: Partial<Record<ChangeType, string>> = {
  add: "Added: ",
  remove: "Removed: ",
};

export const LINE_PREFIX: Record<ChangeType, string> = {
  add: "+",
  remove: "-",
  context: " ",
};

export const LINE_NUMBER_CLASS =
  "inline-block w-8 text-right pr-2 text-muted-foreground select-none";

export function formatHunkHeader(hunk: {
  oldStart: number;
  oldCount: number;
  newStart: number;
  newCount: number;
  heading: string;
}): string {
  return `@@ -${hunk.oldStart},${hunk.oldCount} +${hunk.newStart},${hunk.newCount} @@${hunk.heading ? ` ${hunk.heading}` : ""}`;
}

export function LineContent({
  content,
  wordSegments,
  type,
}: {
  content: string;
  wordSegments: WordSegment[] | undefined;
  type: ChangeType;
}) {
  if (!wordSegments || (type !== "add" && type !== "remove")) {
    return <>{content}</>;
  }

  const bg =
    type === "add"
      ? "bg-success/20 rounded-sm"
      : "bg-destructive/20 rounded-sm";
  return (
    <>
      {wordSegments.map((seg, i) =>
        seg.changed ? (
          <span key={i} className={bg}>
            {seg.text}
          </span>
        ) : (
          seg.text
        ),
      )}
    </>
  );
}

"use client";

import { useMemo, type KeyboardEvent, type RefObject } from "react";
import { cn } from "@/lib/utils";
import { type AnnotatedChange, type ParsedDiff, annotateWordDiff, createWordDiffBudget } from "@/lib/diff";
import { LINE_STYLE, SR_LABEL, LINE_PREFIX, LINE_NUMBER_CLASS, formatHunkHeader, LineContent } from "./diff-view-line";

export function UnifiedView({ parsed, showLineNumbers, disableWordDiff, activeHunk, onKeyDown, containerRef }: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLElement | null>;
}) {
  const hunks = useMemo(
    () => {
      const wordDiffBudget = createWordDiffBudget();
      return parsed.hunks.map((hunk) => ({
        hunk,
        changes: (disableWordDiff ? hunk.changes : annotateWordDiff(hunk.changes, wordDiffBudget)) as AnnotatedChange[],
      }));
    },
    [disableWordDiff, parsed.hunks],
  );

  return (
    <pre
      ref={(node) => {
        containerRef.current = node;
      }}
      aria-label="Unified diff"
      aria-keyshortcuts="j k"
      className="p-2 overflow-x-auto focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      <code>
        {hunks.map(({ hunk, changes }, hi) => {
          return (
            <span key={hi} className="block">
              <span
                data-hunk
                data-diffgazer-navigation-item="button"
                data-value={String(hi)}
                className={cn("block", LINE_STYLE.hunk, activeHunk === String(hi) && "ring-1 ring-ring")}
              >
                {formatHunkHeader(hunk)}
              </span>
              {changes.map((change, ci) => (
                <span key={ci} className={cn("block", LINE_STYLE[change.type])}>
                  {showLineNumbers && (
                    <>
                      <span className={LINE_NUMBER_CLASS} aria-hidden="true">
                        {change.type !== "add" ? change.oldLine : "\u00a0"}
                      </span>
                      <span className={LINE_NUMBER_CLASS} aria-hidden="true">
                        {change.type !== "remove" ? change.newLine : "\u00a0"}
                      </span>
                    </>
                  )}
                  {SR_LABEL[change.type] && <span className="sr-only">{SR_LABEL[change.type]}</span>}
                  <span aria-hidden="true">{LINE_PREFIX[change.type]}</span>
                  <LineContent content={change.content} wordSegments={change.wordSegments} type={change.type} />
                </span>
              ))}
            </span>
          );
        })}
      </code>
    </pre>
  );
}

"use client";

import { useMemo, type KeyboardEvent, type RefObject } from "react";
import { cn } from "@/lib/utils";
import { type ParsedDiff, type SplitCell, toSplitRows } from "@/lib/diff";
import { LINE_STYLE, SR_LABEL, LINE_NUMBER_CLASS, formatHunkHeader, LineContent } from "./diff-view-line";

function SplitCellView({ side, showLineNumbers, disableWordDiff }: {
  side: SplitCell;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
}) {
  if (side.type === "empty") {
    return <span className="block bg-muted/30 pl-2" aria-hidden="true">&nbsp;</span>;
  }

  return (
    <span className={cn("block pl-2", LINE_STYLE[side.type])}>
      {showLineNumbers && (
        <span className={LINE_NUMBER_CLASS} aria-hidden="true">
          {side.lineNumber}
        </span>
      )}
      {SR_LABEL[side.type] && <span className="sr-only">{SR_LABEL[side.type]}</span>}
      <LineContent content={side.content} wordSegments={disableWordDiff ? undefined : side.wordSegments} type={side.type} />
    </span>
  );
}

export function SplitView({ parsed, showLineNumbers, disableWordDiff, activeHunk, onKeyDown, containerRef }: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLElement | null>;
}) {
  const rows = useMemo(
    () => toSplitRows(parsed.hunks, !disableWordDiff),
    [disableWordDiff, parsed.hunks],
  );

  let hunkIndex = -1;

  return (
    <div
      ref={(node) => {
        containerRef.current = node;
      }}
      aria-label="Split diff"
      aria-keyshortcuts="j k"
      className="overflow-x-auto focus:outline-none focus-visible:ring-1 focus-visible:ring-ring"
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      <pre className="p-2">
        <code>
          {rows.map((row, i) => {
            if (row.kind === "separator") {
              hunkIndex++;
              return (
                <span
                  key={i}
                  data-hunk
                  data-diffgazer-navigation-item="button"
                  data-value={String(hunkIndex)}
                  className={cn("block", LINE_STYLE.hunk, activeHunk === String(hunkIndex) && "ring-1 ring-ring")}
                >
                  {formatHunkHeader(row)}
                </span>
              );
            }

            return (
              <span key={i} className="grid grid-cols-2 divide-x divide-border">
                <span role="group" aria-label="Old">
                  <SplitCellView side={row.left} showLineNumbers={showLineNumbers} disableWordDiff={disableWordDiff} />
                </span>
                <span role="group" aria-label="New">
                  <SplitCellView side={row.right} showLineNumbers={showLineNumbers} disableWordDiff={disableWordDiff} />
                </span>
              </span>
            );
          })}
        </code>
      </pre>
    </div>
  );
}
